import java.util.*;

class TreeNode {
    int val;
    TreeNode left, right;
    TreeNode(int val) { this.val = val; }
}

class Solution {
    public List<Integer> levelOrder(TreeNode root) {
        List<Integer> result = new ArrayList<>();
        if (root == null) return result;

        Queue<TreeNode> queue = new LinkedList<>();
        queue.offer(root);

        while (!queue.isEmpty()) {
            TreeNode node = queue.poll();
            result.add(node.val);

            if (node.left != null) 
                queue.offer(node.left);
            if (node.right != null) 
                queue.offer(node.right);
        }
        return result;
    }
}
// Output for tree 15-10-25: [15, 10, 25, 5, 12, 20, 30]

#include <stdio.h>
#include <stdlib.h>

struct Node {
    int data;
    struct Node *left, *right;
};

struct Node* createNode(int val) {
    struct Node* node = (struct Node*)malloc(sizeof(struct Node));
    node->data = val;
    node->left = node->right = NULL;
    return node;
}

void postorder(struct Node* root) {
    if (root == NULL) return;

    postorder(root->left);   // Traverse left subtree
    postorder(root->right);  // Traverse right subtree
    printf("%d ", root->data); // Visit root (process)
}

void deleteTree(struct Node* root) {
    if (root == NULL) return;
    deleteTree(root->left);   // Delete left subtree
    deleteTree(root->right);  // Delete right subtree
    free(root);              // Delete current node
}

// Example: Tree 15->10,25->5,12,20,30
// Output: 5 12 10 20 30 25 15
